// Salvar formulário com loading
<Button variant="primary" isLoading={isSaving} onClick={handleSave}>Salvar</Button>

// Botão de perigo com ícone
<Button variant="danger" leftIcon={<TrashIcon />}>Excluir conta</Button>

// Ação secundária
<Button variant="outline" onClick={onCancel}>Cancelar</Button>

// Campo de e-mail com erro de validação
<Input
  label="E-mail"
  type="email"
  error={errors.email?.message}
  {...register('email')}
/>

// Campo de busca com ícone
<Input
  placeholder="Buscar clientes..."
  leftIcon={<SearchIcon />}
  value={search}
  onChange={e => setSearch(e.target.value)}
/>

// Seleção de estado
<Select
  label="Estado"
  placeholder="Selecione..."
  options={ESTADOS_BR}
  error={errors.estado?.message}
  {...register('estado')}
/>

// Modal de confirmação de exclusão
const [isOpen, setIsOpen] = useState(false);

<Button variant="danger" onClick={() => setIsOpen(true)}>Excluir</Button>

<Modal
  isOpen={isOpen}
  onClose={() => setIsOpen(false)}
  title="Confirmar exclusão"
  footer={
    <>
      <Button variant="outline" onClick={() => setIsOpen(false)}>Cancelar</Button>
      <Button variant="danger" isLoading={isDeleting} onClick={handleDelete}>Excluir</Button>
    </>
  }
>
  <p>Esta ação não pode ser desfeita. Deseja continuar?</p>
</Modal>

// Status de pedido
<Badge variant="success">Aprovado</Badge>
<Badge variant="warning">Pendente</Badge>
<Badge variant="error">Recusado</Badge>

// Role de usuário
<Badge variant="primary">Admin</Badge>

// Tabela de usuários
const columns: Column<User>[] = [
  { header: 'Nome', accessor: 'name' },
  { header: 'E-mail', accessor: 'email' },
  { header: 'Status', accessor: row => <Badge variant={row.active ? 'success' : 'error'}>{row.active ? 'Ativo' : 'Inativo'}</Badge> },
  { header: 'Ações', accessor: row => <Button size="sm" variant="ghost">Editar</Button>, align: 'right' },
];

<DataTable
  columns={columns}
  data={users}
  rowKey="id"
  isLoading={isLoading}
  onRowClick={user => router.push(`/users/${user.id}`)}
/>

// Next.js app/layout.tsx
export default function RootLayout({ children }) {
  return (
    <html>
      <body>
        <ToastProvider>{children}</ToastProvider>
      </body>
    </html>
  );
}

const { success, error } = useToast();

const handleSave = async () => {
  try {
    await saveUser(data);
    success('Usuário salvo com sucesso!');
  } catch {
    error('Erro ao salvar. Tente novamente.');
  }
};

