const [search, setSearch] = useState('');
const debouncedSearch = useDebounce(search, 400);

useEffect(() => {
  if (debouncedSearch) fetchUsers(debouncedSearch);
}, [debouncedSearch]);

const { page, limit, totalPages, nextPage, prevPage, hasNextPage } = usePagination({ total: totalUsers });

useEffect(() => {
  fetchUsers({ page, limit });
}, [page, limit]);

const isMobile = useIsMobile();
const prefersLight = useMediaQuery('(prefers-color-scheme: light)');

return isMobile ? <MobileNav /> : <DesktopSidebar />;

const dropdownRef = useRef<HTMLDivElement>(null);
const [isOpen, setIsOpen] = useState(false);
useClickOutside(dropdownRef, () => setIsOpen(false));

return <div ref={dropdownRef}>{isOpen && <DropdownMenu />}</div>;

const { execute: saveUser, isLoading, isError, error } = useAsync(api.post('/users'));

const handleSubmit = async (data) => {
  await saveUser(data);
  if (!isError) success('Salvo!');
};

